import type { ComponentType } from 'react';

export type ComponentMetrics<P extends object> = {
  SSR?: Array<(props: P) => void>;
};

export const WithTrackerProps: object;

/**
 * Send customizations metrics for components.
 * This function is used to send customization metrics to datadog by the name 'andes.frontend_andes_ui.customization'.
 * It automatically adds the following tags to the metric: application, platform, type.
 *
 * The customization types that are now automatically added are: 'headless'.
 *
 * @example
 * // 'name' should only be used if the component displayName is not the same as the component name or
 * // when the name is composed by multiple words, in this case a hyphen (-) should be used as separator.
 * withTracker(Component, { name: 'Component-Name' })
 */
export const withTracker: <P extends object>(
  component: ComponentType<P>,
  metrics: ComponentMetrics<P>,
) => ComponentType<P & typeof WithTrackerProps>;
